from functools import lru_cache


class Solution:
    def countRoutes(self, locations, start: int, finish: int, fuel: int) -> int:
        MOD = 10 ** 9 + 7
        n = len(locations)

        @lru_cache(maxsize=None)
        def dp(pos, remaining):
            total = 1 if pos == finish else 0
            for nxt in range(n):
                if nxt == pos:
                    continue
                cost = abs(locations[pos] - locations[nxt])
                if cost <= remaining:
                    total += dp(nxt, remaining - cost)
            return total % MOD

        result = dp(start, fuel)
        dp.cache_clear()
        return result

